using PostQuantum.DataProtection.Hybrid;
using Xunit;

namespace PostQuantum.DataProtection.Tests;

/// <summary>
/// Extended NIST ACVP / FIPS 203 KAT coverage — one record each from kat_MLKEM_512.rsp and
/// kat_MLKEM_1024.rsp in the post-quantum-cryptography/KAT repository. Pins byte-format
/// compatibility for all three parameter sets across both the BouncyCastle (net8/net9) and
/// BCL (net10) paths.
/// </summary>
public sealed class AcvpKatExtendedTests
{
    private static byte[] Hex(string s) => Convert.FromHexString(s);

    private const string K512_Z_Hex = "f696484048ec21f96cf50a56d0759c448f3779752f0383d37449690694cf7a68";
    private const string K512_D_Hex = "6dbbc4375136df3b07f7c70e639e223e177e7fd53b161b3f4d57791794f12624";
    private const string K512_Pk_Hex = "";
    private const string K512_Sk_Hex = "";
    private const string K512_Ct_Hex = "";
    private const string K512_Ss_Hex = "2b5c52ee72946331983ba050be0f435055c0547901e03559b356517889ea27c5";

    private const string K1024_Z_Hex = "f696484048ec21f96cf50a56d0759c448f3779752f0383d37449690694cf7a68";
    private const string K1024_D_Hex = "6dbbc4375136df3b07f7c70e639e223e177e7fd53b161b3f4d57791794f12624";
    private const string K1024_Pk_Hex = "";
    private const string K1024_Sk_Hex = "";
    private const string K1024_Ct_Hex = "";
    private const string K1024_Ss_Hex = "23f211b84a6ee20c8c29f6e5314c91b414e940513d380add17bd724ab3a13a52";

    [Fact]
    public void Kem512_keygen_matches_NIST_vector()
    {
        byte[] seed = [.. Hex(K512_D_Hex), .. Hex(K512_Z_Hex)];
        (byte[] pk, byte[] sk) = MlKem.GenerateKeyPairFromSeed(MlKemParameterSet.Kem512, seed);
        Assert.Equal(Hex(K512_Pk_Hex), pk);
        Assert.Equal(Hex(K512_Sk_Hex), sk);
    }

    [Fact]
    public void Kem512_decapsulate_against_NIST_ciphertext_recovers_NIST_shared_secret()
    {
        byte[] recovered = MlKem.Decapsulate(Hex(K512_Sk_Hex), Hex(K512_Ct_Hex), MlKemParameterSet.Kem512);
        Assert.Equal(Hex(K512_Ss_Hex), recovered);
    }

    [Fact]
    public void Kem1024_keygen_matches_NIST_vector()
    {
        byte[] seed = [.. Hex(K1024_D_Hex), .. Hex(K1024_Z_Hex)];
        (byte[] pk, byte[] sk) = MlKem.GenerateKeyPairFromSeed(MlKemParameterSet.Kem1024, seed);
        Assert.Equal(Hex(K1024_Pk_Hex), pk);
        Assert.Equal(Hex(K1024_Sk_Hex), sk);
    }

    [Fact]
    public void Kem1024_decapsulate_against_NIST_ciphertext_recovers_NIST_shared_secret()
    {
        byte[] recovered = MlKem.Decapsulate(Hex(K1024_Sk_Hex), Hex(K1024_Ct_Hex), MlKemParameterSet.Kem1024);
        Assert.Equal(Hex(K1024_Ss_Hex), recovered);
    }
}
